  1	import * as _ from 'lodash-es';
  2	import {
  3	  consoleFetchJSON,
  4	  Silence,
  5	  SilenceStates,
  6	  useActiveNamespace,
  7	} from '@openshift-console/dynamic-plugin-sdk';
  8	import {
  9	  ActionGroup,
 10	  Alert,
 11	  Button,
 12	  Checkbox,
 13	  DescriptionList,
 14	  DescriptionListDescription,
 15	  Divider,
 16	  Form,
 17	  FormGroup,
 18	  FormHelperText,
 19	  Grid,
 20	  GridItem,
 21	  HelperText,
 22	  HelperTextItem,
 23	  Icon,
 24	  MenuToggle,
 25	  MenuToggleElement,
 26	  PageSection,
 27	  PageSectionVariants,
 28	  Select,
 29	  SelectList,
 30	  SelectOption,
 31	  TextArea,
 32	  TextInput,
 33	  Timestamp,
 34	  Title,
 35	  Tooltip,
 36	  ValidatedOptions,
 37	} from '@patternfly/react-core';
 38	import { MinusCircleIcon, PlusCircleIcon } from '@patternfly/react-icons';
 39	import * as React from 'react';
 40	import { Helmet } from 'react-helmet';
 41	import { Trans, useTranslation } from 'react-i18next';
 42	import { useDispatch, useSelector } from 'react-redux';
 43	import { RouteComponentProps, withRouter } from 'react-router-dom';
 44	
 45	// TODO: These will be available in future versions of the plugin SDK
 46	const getUser = (state) => state.sdkCore?.user;
 47	
 48	import { ExternalLink } from './console/utils/link';
 49	import { getAllQueryArguments } from './console/utils/router';
 50	
 51	import { useBoolean } from './hooks/useBoolean';
 52	import { Silences } from './types';
 53	import { refreshSilences, SilenceResource, silenceState } from './utils';
 54	import {
 55	  getFetchSilenceAlertUrl,
 56	  getLegacyObserveState,
 57	  getSilenceAlertUrl,
 58	  usePerspective,
 59	} from './hooks/usePerspective';
 60	import { MonitoringState } from '../reducers/observe';
 61	import { StatusBox } from './console/console-shared/src/components/status/StatusBox';
 62	import {
 63	  formatPrometheusDuration,
 64	  parsePrometheusDuration,
 65	} from './console/console-shared/src/datetime/prometheus';
 66	import withFallback from './console/console-shared/error/fallbacks/withFallback';
 67	
 68	const pad = (i: number): string => (i < 10 ? `0${i}` : String(i));
 69	
 70	const formatDate = (d: Date): string =>
 71	  `${d.getFullYear()}/${pad(d.getMonth() + 1)}/${pad(d.getDate())} ${pad(d.getHours())}:${pad(
 72	    d.getMinutes(),
 73	  )}:${pad(d.getSeconds())}`;
 74	
 75	const DatetimeTextInput = (props) => {
 76	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 77	
 78	  const pattern =
 79	    '\\d{4}/(0?[1-9]|1[012])/(0?[1-9]|[12]\\d|3[01]) (0?\\d|1\\d|2[0-3]):[0-5]\\d(:[0-5]\\d)?';
 80	  const isValid = new RegExp(`^${pattern}$`).test(props.value) || props.value === 'Now';
 81	
 82	  const date = props.value === 'Now' ? new Date() : new Date(props.value);
 83	
 84	  return (
 85	    <Tooltip
 86	      content={
 87	        <Timestamp date={date}>{isValid ? date.toISOString() : t('Invalid date / time')}</Timestamp>
 88	      }
 89	    >
 90	      <TextInput
 91	        {...props}
 92	        aria-label={t('Datetime')}
 93	        data-test-id="silence-datetime"
 94	        validated={isValid || !!props.isDisabled ? 'default' : 'error'}
 95	        pattern={pattern}
 96	        placeholder="YYYY/MM/DD hh:mm:ss"
 97	      />
 98	    </Tooltip>
 99	  );
100	};
101	
102	const NegativeMatcherHelp = () => {
103	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
104	
105	  return (
106	    <DescriptionList>
107	      <DescriptionListDescription className="pf-v6-u-text-align-center">
108	        {t('Select the negative matcher option to update the label value to a not equals matcher.')}
109	      </DescriptionListDescription>
110	      <DescriptionListDescription className="pf-v6-u-text-align-center">
111	        {t(
112	          'If both the RegEx and negative matcher options are selected, the label value must not match the regular expression.',
113	        )}
114	      </DescriptionListDescription>
115	    </DescriptionList>
116	  );
117	};
118	
119	type SilenceFormProps = RouteComponentProps & {
120	  defaults: any;
121	  Info?: React.ComponentType;
122	  title: string;
123	};
124	
125	const SilenceForm_: React.FC<SilenceFormProps> = ({ defaults, history, Info, title }) => {
126	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
127	
128	  const durationOff = '-';
129	  const durations = {
130	    [durationOff]: durationOff,
131	    '30m': t('30m'),
132	    '1h': t('1h'),
133	    '2h': t('2h'),
134	    '6h': t('6h'),
135	    '12h': t('12h'),
136	    '1d': t('1d'),
137	    '2d': t('2d'),
138	    '1w': t('1w'),
139	  };
140	
141	  const now = new Date();
142	
143	  // Default to starting now if we have no default start time or if the default start time is in the
144	  // past (because Alertmanager will change a time in the past to the current time on save anyway)
145	  const defaultIsStartNow = _.isEmpty(defaults.startsAt) || new Date(defaults.startsAt) < now;
146	
147	  let defaultDuration = _.isEmpty(defaults.endsAt) ? '2h' : durationOff;
148	
149	  // If we have both a default start and end time and the difference between them exactly matches
150	  // one of the duration options, automatically select that option in the duration menu
151	  if (!defaultIsStartNow && defaults.startsAt && defaults.endsAt) {
152	    const durationFromDefaults = formatPrometheusDuration(
153	      Date.parse(defaults.endsAt) - Date.parse(defaults.startsAt),
154	    );
155	    if (Object.keys(durations).includes(durationFromDefaults)) {
156	      defaultDuration = durationFromDefaults;
157	    }
158	  }
159	
160	  const dispatch = useDispatch();
161	
162	  const { perspective, silencesKey } = usePerspective();
163	
164	  const [isOpen, setIsOpen, , setClosed] = useBoolean(false);
165	
166	  const [comment, setComment] = React.useState(defaults.comment ?? '');
167	  const [createdBy, setCreatedBy] = React.useState(defaults.createdBy ?? '');
168	  const [duration, setDuration] = React.useState(defaultDuration);
169	  const [endsAt, setEndsAt] = React.useState(
170	    defaults.endsAt ?? formatDate(new Date(new Date(now).setHours(now.getHours() + 2))),
171	  );
172	  const [error, setError] = React.useState<string>();
173	  const [inProgress, setInProgress] = React.useState(false);
174	  const [isStartNow, setIsStartNow] = React.useState(defaultIsStartNow);
175	  const [matchers, setMatchers] = React.useState(
176	    defaults.matchers ?? [{ isRegex: false, name: '', value: '' }],
177	  );
178	  const [startsAt, setStartsAt] = React.useState(defaults.startsAt ?? formatDate(now));
179	  const user = useSelector(getUser);
180	  const [namespace] = useActiveNamespace();
181	
182	  React.useEffect(() => {
183	    if (!createdBy && user) {
184	      setCreatedBy(user.metadata?.name || user.username);
185	    }
186	    // eslint-disable-next-line react-hooks/exhaustive-deps
187	  }, [user]);
188	
189	  const getEndsAtValue = (): string => {
190	    const startsAtDate = Date.parse(startsAt);
191	    return startsAtDate
192	      ? formatDate(new Date(startsAtDate + parsePrometheusDuration(duration)))
193	      : '-';
194	  };
195	
196	  const setMatcherField = (i: number, field: string, v: any): void => {
197	    const newMatchers = _.clone(matchers);
198	    _.set(newMatchers, [i, field], v);
199	    setMatchers(newMatchers);
200	  };
201	
202	  const addMatcher = (): void => {
203	    setMatchers([...matchers, { isRegex: false, name: '', value: '' }]);
204	  };
205	
206	  const removeMatcher = (i: number): void => {
207	    const newMatchers = _.clone(matchers);
208	    newMatchers.splice(i, 1);
209	
210	    // If all matchers have been removed, add back a single blank matcher
211	    setMatchers(_.isEmpty(newMatchers) ? [{ isRegex: false, name: '', value: '' }] : newMatchers);
212	  };
213	
214	  const onSubmit: React.FormEventHandler<HTMLFormElement> = (e) => {
215	    e.preventDefault();
216	
217	    // Don't allow comments to only contain whitespace
218	    if (_.trim(comment) === '') {
219	      setError('Comment is required.');
220	      return;
221	    }
222	
223	    const url = getFetchSilenceAlertUrl(perspective, namespace);
224	    if (!url) {
225	      setError('Alertmanager URL not set');
226	      return;
227	    }
228	
229	    setInProgress(true);
230	
231	    const saveStartsAt: Date = isStartNow ? new Date() : new Date(startsAt);
232	    const saveEndsAt: Date =
233	      duration === durationOff
234	        ? new Date(endsAt)
235	        : new Date(saveStartsAt.getTime() + parsePrometheusDuration(duration));
236	
237	    const body = {
238	      comment,
239	      createdBy,
240	      endsAt: saveEndsAt.toISOString(),
241	      id: defaults.id,
242	      matchers,
243	      startsAt: saveStartsAt.toISOString(),
244	    };
245	
246	    consoleFetchJSON
247	      .post(getFetchSilenceAlertUrl(perspective, namespace), body)
248	      .then(({ silenceID }) => {
249	        setError(undefined);
250	        refreshSilences(dispatch, perspective, silencesKey, namespace);
251	        history.push(getSilenceAlertUrl(perspective, silenceID, namespace));
252	      })
253	      .catch((err) => {
254	        const errorMessage =
255	          typeof _.get(err, 'json') === 'string'
256	            ? _.get(err, 'json')
257	            : err.message || 'Error saving Silence';
258	        setError(errorMessage);
259	        setInProgress(false);
260	      });
261	  };
262	
263	  const selectOptions = _.map(durations, (displayText, key) => (
264	    <SelectOption key={key} value={key}>
265	      {displayText}
266	    </SelectOption>
267	  ));
268	
269	  return (
270	    <>
271	      <Helmet>
272	        <title>{title}</title>
273	      </Helmet>
274	      <PageSection variant={PageSectionVariants.light}>
275	        <Title headingLevel="h1">{title}</Title>
276	        <HelperText>
277	          <HelperTextItem className="monitoring__title-help-text">
278	            {t(
279	              'Silences temporarily mute alerts based on a set of label selectors that you define. Notifications will not be sent for alerts that match all the listed values or regular expressions.',
280	            )}
281	          </HelperTextItem>
282	        </HelperText>
283	      </PageSection>
284	      <Divider />
285	
286	      <PageSection variant={PageSectionVariants.light}>
287	        <Form onSubmit={onSubmit} maxWidth="950px">
288	          {Info && <Info />}
289	          {error && <Alert variant="danger" isInline title={error} />}
290	          <Title headingLevel="h2">{t('Duration')}</Title>
291	          <Grid hasGutter>
292	            <GridItem sm={4} md={5}>
293	              <FormGroup label={t('Silence alert from...')}>
294	                {isStartNow ? (
295	                  <DatetimeTextInput isDisabled data-test="silence-from" value={t('Now')} />
296	                ) : (
297	                  <DatetimeTextInput
298	                    data-test="silence-from"
299	                    isRequired
300	                    onChange={(_event, value: string) => setStartsAt(value)}
301	                    value={startsAt}
302	                  />
303	                )}
304	              </FormGroup>
305	            </GridItem>
306	            <GridItem sm={4} md={2}>
307	              <FormGroup label={t('For...')}>
308	                <Select
309	                  data-test="silence-for"
310	                  isOpen={isOpen}
311	                  onSelect={(event: React.MouseEvent | React.ChangeEvent, value: string) => {
312	                    setDuration(value);
313	                    setClosed();
314	                  }}
315	                  toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
316	                    <MenuToggle
317	                      ref={toggleRef}
318	                      onClick={setIsOpen}
319	                      isExpanded={isOpen}
320	                      isFullWidth
321	                      data-test="silence-for-toggle"
322	                    >
323	                      {duration}
324	                    </MenuToggle>
325	                  )}
326	                  onOpenChange={setIsOpen}
327	                >
328	                  <SelectList>{selectOptions}</SelectList>
329	                </Select>
330	              </FormGroup>
331	            </GridItem>
332	            <GridItem sm={4} md={5}>
333	              <FormGroup label={t('Until...')}>
334	                {duration === durationOff ? (
335	                  <DatetimeTextInput
336	                    data-test="silence-until"
337	                    isRequired
338	                    onChange={(_event, value: string) => setEndsAt(value)}
339	                    value={endsAt}
340	                  />
341	                ) : (
342	                  <DatetimeTextInput
343	                    data-test="silence-until"
344	                    isDisabled
345	                    value={
346	                      isStartNow
347	                        ? t('{{duration}} from now', { duration: durations[duration] })
348	                        : getEndsAtValue()
349	                    }
350	                  />
351	                )}
352	              </FormGroup>
353	            </GridItem>
354	          </Grid>
355	          <FormGroup role="group">
356	            <Checkbox
357	              id="start-immediately"
358	              label={t('Start immediately')}
359	              isChecked={isStartNow}
360	              onChange={(e) => setIsStartNow(e.currentTarget.checked)}
361	            />
362	          </FormGroup>
363	
364	          <Title headingLevel="h2">{t('Alert labels')}</Title>
365	          <FormHelperText>
366	            <HelperText>
367	              <HelperTextItem variant="indeterminate">
368	                <Trans t={t}>
369	                  Alerts with labels that match these selectors will be silenced instead of firing.
370	                  Label values can be matched exactly or with a{' '}
371	                  <ExternalLink
372	                    href="https://github.com/google/re2/wiki/Syntax"
373	                    text={t('regular expression')}
374	                  />
375	                </Trans>
376	              </HelperTextItem>
377	            </HelperText>
378	          </FormHelperText>
379	
380	          {_.map(matchers, (matcher, i: number) => (
381	            <Grid key={i} sm={12} md={4} hasGutter>
382	              <GridItem>
383	                <FormGroup label={t('Label name')}>
384	                  <TextInput
385	                    aria-label={t('Label name')}
386	                    isRequired
387	                    onChange={(_e, v: string) =>
388	                      typeof _e === 'string'
389	                        ? setMatcherField(i, 'name', _e)
390	                        : setMatcherField(i, 'name', v)
391	                    }
392	                    placeholder={t('Name')}
393	                    value={matcher.name}
394	                  />
395	                </FormGroup>
396	              </GridItem>
397	              <GridItem>
398	                <FormGroup label={t('Label value')}>
399	                  <TextInput
400	                    aria-label={t('Label value')}
401	                    isRequired
402	                    onChange={(_e, v: string) =>
403	                      typeof _e === 'string'
404	                        ? setMatcherField(i, 'value', _e)
405	                        : setMatcherField(i, 'value', v)
406	                    }
407	                    placeholder={t('Value')}
408	                    value={matcher.value}
409	                  />
410	                </FormGroup>
411	              </GridItem>
412	              <GridItem>
413	                <FormGroup>
414	                  <div className="monitoring-silence-alert__label-options">
415	                    <FormGroup role="group" isInline>
416	                      <Checkbox
417	                        id="regex"
418	                        label={t('RegEx')}
419	                        isChecked={matcher.isRegex}
420	                        onChange={(e) => setMatcherField(i, 'isRegex', e.currentTarget.checked)}
421	                      />
422	                      <Tooltip content={<NegativeMatcherHelp />}>
423	                        <Checkbox
424	                          id="negative-matcher"
425	                          label={t('Negative matcher')}
426	                          isChecked={matcher.isEqual === false}
427	                          onChange={(e) => setMatcherField(i, 'isEqual', !e.currentTarget.checked)}
428	                        />
429	                      </Tooltip>
430	                    </FormGroup>
431	                    <Tooltip content={t('Remove')}>
432	                      <Button
433	                        type="button"
434	                        onClick={() => removeMatcher(i)}
435	                        aria-label={t('Remove')}
436	                        variant="plain"
437	                      >
438	                        <MinusCircleIcon />
439	                      </Button>
440	                    </Tooltip>
441	                  </div>
442	                </FormGroup>
443	              </GridItem>
444	            </Grid>
445	          ))}
446	
447	          <FormGroup>
448	            <Button
449	              className="pf-v5-m-link--align-left"
450	              onClick={addMatcher}
451	              type="button"
452	              variant="link"
453	              isInline
454	            >
455	              <Icon isInline size="lg" iconSize="md">
456	                <PlusCircleIcon />
457	              </Icon>
458	              {t('Add label')}
459	            </Button>
460	          </FormGroup>
461	
462	          <Title headingLevel="h2">{t('Info')}</Title>
463	          <FormGroup label={t('Creator')} isRequired>
464	            <TextInput
465	              aria-label={t('Creator')}
466	              isRequired
467	              onChange={(_e, v: string) =>
468	                typeof _e === 'string' ? setCreatedBy(_e) : setCreatedBy(v)
469	              }
470	              value={createdBy}
471	            />
472	          </FormGroup>
473	          <FormGroup label={t('Comment')} isRequired>
474	            <TextArea
475	              aria-label={t('Comment')}
476	              isRequired
477	              onChange={(_e, v: string) =>
478	                typeof _e === 'string' ? setComment(_e) : setComment(v)
479	              }
480	              data-test="silence-comment"
481	              value={comment}
482	              validated={error ? ValidatedOptions.error : ValidatedOptions.default}
483	            />
484	          </FormGroup>
485	          <ActionGroup>
486	            <Button type="submit" variant="primary" isDisabled={inProgress}>
487	              {t('Silence')}
488	            </Button>
489	            <Button onClick={history.goBack} variant="secondary" isDisabled={inProgress}>
490	              {t('Cancel')}
491	            </Button>
492	          </ActionGroup>
493	        </Form>
494	      </PageSection>
495	    </>
496	  );
497	};
498	const SilenceForm = withFallback(withRouter(SilenceForm_));
499	
500	const EditInfo = () => {
501	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
502	
503	  return (
504	    <Alert isInline title={t('Overwriting current silence')} variant="info">
505	      {t(
506	        'When changes are saved, the currently existing silence will be expired and a new silence with the new configuration will take its place.',
507	      )}
508	    </Alert>
509	  );
510	};
511	
512	export const EditSilence = ({ match }) => {
513	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
514	  const { silencesKey, perspective } = usePerspective();
515	
516	  const silences: Silences = useSelector((state: MonitoringState) =>
517	    getLegacyObserveState(perspective, state)?.get(silencesKey),
518	  );
519	
520	  const silence: Silence = _.find(silences?.data, { id: match.params.id });
521	  const isExpired = silenceState(silence) === SilenceStates.Expired;
522	  const defaults = _.pick(silence, [
523	    'comment',
524	    'createdBy',
525	    'endsAt',
526	    'id',
527	    'matchers',
528	    'startsAt',
529	  ]);
530	  defaults.startsAt = isExpired ? undefined : formatDate(new Date(defaults.startsAt));
531	  defaults.endsAt = isExpired ? undefined : formatDate(new Date(defaults.endsAt));
532	
533	  return (
534	    <StatusBox
535	      data={silence}
536	      label={SilenceResource.label}
537	      loaded={silences?.loaded}
538	      loadError={silences?.loadError}
539	    >
540	      <SilenceForm
541	        defaults={defaults}
542	        Info={isExpired ? undefined : EditInfo}
543	        title={isExpired ? t('Recreate silence') : t('Edit silence')}
544	      />
545	    </StatusBox>
546	  );
547	};
548	
549	export const CreateSilence = () => {
550	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
551	
552	  const matchers = _.map(getAllQueryArguments(), (value, name) => ({
553	    name,
554	    value,
555	    isRegex: false,
556	  }));
557	
558	  return _.isEmpty(matchers) ? (
559	    <SilenceForm defaults={{}} title={t('Create silence')} />
560	  ) : (
561	    <SilenceForm defaults={{ matchers }} title={t('Silence alert')} />
562	  );
563	};

