125	const SilenceForm_: React.FC<SilenceFormProps> = ({ defaults, history, Info, title }) => {
126	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
127	
128	  const durationOff = '-';
129	  const durations = {
130	    [durationOff]: durationOff,
131	    '30m': t('30m'),
132	    '1h': t('1h'),
133	    '2h': t('2h'),
134	    '6h': t('6h'),
135	    '12h': t('12h'),
136	    '1d': t('1d'),
137	    '2d': t('2d'),
138	    '1w': t('1w'),
139	  };
140	
141	  const now = new Date();
142	
143	  // Default to starting now if we have no default start time or if the default start time is in the
144	  // past (because Alertmanager will change a time in the past to the current time on save anyway)
145	  const defaultIsStartNow = _.isEmpty(defaults.startsAt) || new Date(defaults.startsAt) < now;
146	
147	  let defaultDuration = _.isEmpty(defaults.endsAt) ? '2h' : durationOff;
148	
149	  // If we have both a default start and end time and the difference between them exactly matches
150	  // one of the duration options, automatically select that option in the duration menu
151	  if (!defaultIsStartNow && defaults.startsAt && defaults.endsAt) {
152	    const durationFromDefaults = formatPrometheusDuration(
153	      Date.parse(defaults.endsAt) - Date.parse(defaults.startsAt),
154	    );
155	    if (Object.keys(durations).includes(durationFromDefaults)) {
156	      defaultDuration = durationFromDefaults;
157	    }
158	  }
159	
160	  const dispatch = useDispatch();
161	
162	  const { perspective, silencesKey } = usePerspective();
163	
164	  const [isOpen, setIsOpen, , setClosed] = useBoolean(false);
165	
166	  const [comment, setComment] = React.useState(defaults.comment ?? '');
167	  const [createdBy, setCreatedBy] = React.useState(defaults.createdBy ?? '');
168	  const [duration, setDuration] = React.useState(defaultDuration);
169	  const [endsAt, setEndsAt] = React.useState(
170	    defaults.endsAt ?? formatDate(new Date(new Date(now).setHours(now.getHours() + 2))),
171	  );
172	  const [error, setError] = React.useState<string>();
173	  const [inProgress, setInProgress] = React.useState(false);
174	  const [isStartNow, setIsStartNow] = React.useState(defaultIsStartNow);
175	  const [matchers, setMatchers] = React.useState(
176	    defaults.matchers ?? [{ isRegex: false, name: '', value: '' }],
177	  );
178	  const [startsAt, setStartsAt] = React.useState(defaults.startsAt ?? formatDate(now));
179	  const user = useSelector(getUser);
180	  const [namespace] = useActiveNamespace();
181	
182	  React.useEffect(() => {
183	    if (!createdBy && user) {
184	      setCreatedBy(user.metadata?.name || user.username);
185	    }
186	    // eslint-disable-next-line react-hooks/exhaustive-deps
187	  }, [user]);
188	
189	  const getEndsAtValue = (): string => {
190	    const startsAtDate = Date.parse(startsAt);
191	    return startsAtDate
192	      ? formatDate(new Date(startsAtDate + parsePrometheusDuration(duration)))
193	      : '-';
194	  };
195	
196	  const setMatcherField = (i: number, field: string, v: any): void => {
197	    const newMatchers = _.clone(matchers);
198	    _.set(newMatchers, [i, field], v);
199	    setMatchers(newMatchers);
200	  };
201	
202	  const addMatcher = (): void => {
203	    setMatchers([...matchers, { isRegex: false, name: '', value: '' }]);
204	  };
205	
206	  const removeMatcher = (i: number): void => {
207	    const newMatchers = _.clone(matchers);
208	    newMatchers.splice(i, 1);
209	
210	    // If all matchers have been removed, add back a single blank matcher
211	    setMatchers(_.isEmpty(newMatchers) ? [{ isRegex: false, name: '', value: '' }] : newMatchers);
212	  };
213	
214	  const onSubmit: React.FormEventHandler<HTMLFormElement> = (e) => {
215	    e.preventDefault();
216	
217	    // Don't allow comments to only contain whitespace
218	    if (_.trim(comment) === '') {
219	      setError('Comment is required.');
220	      return;
221	    }
222	
223	    const url = getFetchSilenceAlertUrl(perspective, namespace);
224	    if (!url) {
225	      setError('Alertmanager URL not set');
226	      return;
227	    }
228	
229	    setInProgress(true);
230	
231	    const saveStartsAt: Date = isStartNow ? new Date() : new Date(startsAt);
232	    const saveEndsAt: Date =
233	      duration === durationOff
234	        ? new Date(endsAt)
235	        : new Date(saveStartsAt.getTime() + parsePrometheusDuration(duration));
236	
237	    const body = {
238	      comment,
239	      createdBy,
240	      endsAt: saveEndsAt.toISOString(),
241	      id: defaults.id,
242	      matchers,
243	      startsAt: saveStartsAt.toISOString(),
244	    };
245	
246	    consoleFetchJSON
247	      .post(getFetchSilenceAlertUrl(perspective, namespace), body)
248	      .then(({ silenceID }) => {
249	        setError(undefined);
250	        refreshSilences(dispatch, perspective, silencesKey, namespace);
251	        history.push(getSilenceAlertUrl(perspective, silenceID, namespace));
252	      })
253	      .catch((err) => {
254	        const errorMessage =
255	          typeof _.get(err, 'json') === 'string'
256	            ? _.get(err, 'json')
257	            : err.message || 'Error saving Silence';
258	        setError(errorMessage);
259	        setInProgress(false);
260	      });
261	  };
262	
263	  const selectOptions = _.map(durations, (displayText, key) => (
264	    <SelectOption key={key} value={key}>
265	      {displayText}
266	    </SelectOption>
267	  ));
268	
269	  return (
270	    <>
271	      <Helmet>
272	        <title>{title}</title>
273	      </Helmet>
274	      <PageSection variant={PageSectionVariants.light}>
275	        <Title headingLevel="h1">{title}</Title>
276	        <HelperText>
277	          <HelperTextItem className="monitoring__title-help-text">
278	            {t(
279	              'Silences temporarily mute alerts based on a set of label selectors that you define. Notifications will not be sent for alerts that match all the listed values or regular expressions.',
280	            )}
281	          </HelperTextItem>
282	        </HelperText>
283	      </PageSection>
284	      <Divider />
285	
286	      <PageSection variant={PageSectionVariants.light}>
287	        <Form onSubmit={onSubmit} maxWidth="950px">
288	          {Info && <Info />}
289	          {error && <Alert variant="danger" isInline title={error} />}
290	          <Title headingLevel="h2">{t('Duration')}</Title>
291	          <Grid hasGutter>
292	            <GridItem sm={4} md={5}>
293	              <FormGroup label={t('Silence alert from...')}>
294	                {isStartNow ? (
295	                  <DatetimeTextInput isDisabled data-test="silence-from" value={t('Now')} />
296	                ) : (
297	                  <DatetimeTextInput
298	                    data-test="silence-from"
299	                    isRequired
300	                    onChange={(_event, value: string) => setStartsAt(value)}
301	                    value={startsAt}
302	                  />
303	                )}
304	              </FormGroup>
305	            </GridItem>
306	            <GridItem sm={4} md={2}>
307	              <FormGroup label={t('For...')}>
308	                <Select
309	                  data-test="silence-for"
310	                  isOpen={isOpen}
311	                  onSelect={(event: React.MouseEvent | React.ChangeEvent, value: string) => {
312	                    setDuration(value);
313	                    setClosed();
314	                  }}
315	                  toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
316	                    <MenuToggle
317	                      ref={toggleRef}
318	                      onClick={setIsOpen}
319	                      isExpanded={isOpen}
320	                      isFullWidth
321	                      data-test="silence-for-toggle"
322	                    >
323	                      {duration}
324	                    </MenuToggle>
325	                  )}
326	                  onOpenChange={setIsOpen}
327	                >
328	                  <SelectList>{selectOptions}</SelectList>
329	                </Select>
330	              </FormGroup>
331	            </GridItem>
332	            <GridItem sm={4} md={5}>
333	              <FormGroup label={t('Until...')}>
334	                {duration === durationOff ? (
335	                  <DatetimeTextInput
336	                    data-test="silence-until"
337	                    isRequired
338	                    onChange={(_event, value: string) => setEndsAt(value)}
339	                    value={endsAt}
340	                  />
341	                ) : (
342	                  <DatetimeTextInput
343	                    data-test="silence-until"
344	                    isDisabled
345	                    value={
346	                      isStartNow
347	                        ? t('{{duration}} from now', { duration: durations[duration] })
348	                        : getEndsAtValue()
349	                    }
350	                  />
351	                )}
352	              </FormGroup>
353	            </GridItem>
354	          </Grid>
355	          <FormGroup role="group">
356	            <Checkbox
357	              id="start-immediately"
358	              label={t('Start immediately')}
359	              isChecked={isStartNow}
360	              onChange={(e) => setIsStartNow(e.currentTarget.checked)}
361	            />
362	          </FormGroup>
363	
364	          <Title headingLevel="h2">{t('Alert labels')}</Title>
365	          <FormHelperText>
366	            <HelperText>
367	              <HelperTextItem variant="indeterminate">
368	                <Trans t={t}>
369	                  Alerts with labels that match these selectors will be silenced instead of firing.
370	                  Label values can be matched exactly or with a{' '}
371	                  <ExternalLink
372	                    href="https://github.com/google/re2/wiki/Syntax"
373	                    text={t('regular expression')}
374	                  />
375	                </Trans>
376	              </HelperTextItem>
377	            </HelperText>
378	          </FormHelperText>
379	
380	          {_.map(matchers, (matcher, i: number) => (
381	            <Grid key={i} sm={12} md={4} hasGutter>
382	              <GridItem>
383	                <FormGroup label={t('Label name')}>
384	                  <TextInput
385	                    aria-label={t('Label name')}
386	                    isRequired
387	                    onChange={(_e, v: string) =>
388	                      typeof _e === 'string'
389	                        ? setMatcherField(i, 'name', _e)
390	                        : setMatcherField(i, 'name', v)
391	                    }
392	                    placeholder={t('Name')}
393	                    value={matcher.name}
394	                  />
395	                </FormGroup>
396	              </GridItem>
397	              <GridItem>
398	                <FormGroup label={t('Label value')}>
399	                  <TextInput
400	                    aria-label={t('Label value')}
401	                    isRequired
402	                    onChange={(_e, v: string) =>
403	                      typeof _e === 'string'
404	                        ? setMatcherField(i, 'value', _e)
405	                        : setMatcherField(i, 'value', v)
406	                    }
407	                    placeholder={t('Value')}
408	                    value={matcher.value}
409	                  />
410	                </FormGroup>
411	              </GridItem>
412	              <GridItem>
413	                <FormGroup>
414	                  <div className="monitoring-silence-alert__label-options">
415	                    <FormGroup role="group" isInline>
416	                      <Checkbox
