219	  const onSubmit: React.FormEventHandler<HTMLFormElement> = (e) => {
220	    e.preventDefault();
221	
222	    // Don't allow comments to only contain whitespace
223	    if (_.trim(comment) === '') {
224	      setError('Comment is required.');
225	      return;
226	    }
227	
228	    const url = getFetchSilenceAlertUrl(perspective, namespace);
229	    if (!url) {
230	      setError('Alertmanager URL not set');
231	      return;
232	    }
233	
234	    setInProgress(true);
235	
236	    const saveStartsAt: Date = isStartNow ? new Date() : new Date(startsAt);
237	    const saveEndsAt: Date =
238	      duration === durationOff
239	        ? new Date(endsAt)
240	        : new Date(saveStartsAt.getTime() + parsePrometheusDuration(duration));
241	
242	    const body = {
243	      comment,
244	      createdBy,
245	      endsAt: saveEndsAt.toISOString(),
246	      id: defaults.id,
247	      matchers,
248	      startsAt: saveStartsAt.toISOString(),
249	    };
