251	    consoleFetchJSON
252	      .post(getFetchSilenceAlertUrl(perspective, namespace), body)
253	      .then(({ silenceID }) => {
254	        setError(undefined);
255	        refreshSilences(dispatch, perspective, silencesKey, namespace);
256	        history.push(getSilenceAlertUrl(perspective, silenceID, namespace));
257	      })
258	      .catch((err) => {
259	        const errorMessage =
260	          typeof _.get(err, 'json') === 'string'
261	            ? _.get(err, 'json')
262	            : err.message || 'Error saving Silence';
263	        setError(errorMessage);
264	        setInProgress(false);
265	      });
266	  };
267	
268	  const selectOptions = _.map(durations, (displayText, key) => (
269	    <SelectOption key={key} value={key}>
270	      {displayText}
271	    </SelectOption>
272	  ));
273	
274	  return (
275	    <>
276	      <Helmet>
277	        <title>{title}</title>
278	      </Helmet>
279	      <PageSection variant={PageSectionVariants.light}>
280	        <Title headingLevel="h1">{title}</Title>
281	        <HelperText>
282	          <HelperTextItem className="monitoring__title-help-text">
283	            {t(
284	              'Silences temporarily mute alerts based on a set of label selectors that you define. Notifications will not be sent for alerts that match all the listed values or regular expressions.',
285	            )}
286	          </HelperTextItem>
287	        </HelperText>
288	      </PageSection>
289	      <Divider />
290	
291	      <PageSection variant={PageSectionVariants.light}>
292	        <Form onSubmit={onSubmit} maxWidth="950px">
293	          {Info && <Info />}
294	          {error && <Alert variant="danger" isInline title={error} />}
295	          <Title headingLevel="h2">{t('Duration')}</Title>
296	          <Grid hasGutter>
297	            <GridItem sm={4} md={5}>
298	              <FormGroup label={t('Silence alert from...')}>
299	                {isStartNow ? (
300	                  <DatetimeTextInput isDisabled data-test="silence-from" value={t('Now')} />
301	                ) : (
302	                  <DatetimeTextInput
303	                    data-test="silence-from"
304	                    isRequired
305	                    onChange={(_event, value: string) => setStartsAt(value)}
306	                    value={startsAt}
307	                  />
308	                )}
309	              </FormGroup>
310	            </GridItem>
311	            <GridItem sm={4} md={2}>
312	              <FormGroup label={t('For...')}>
313	                <Select
314	                  data-test="silence-for"
315	                  isOpen={isOpen}
316	                  onSelect={(event: React.MouseEvent | React.ChangeEvent, value: string) => {
317	                    setDuration(value);
318	                    setClosed();
319	                  }}
320	                  toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
321	                    <MenuToggle
322	                      ref={toggleRef}
323	                      onClick={setIsOpen}
324	                      isExpanded={isOpen}
325	                      isFullWidth
326	                      data-test="silence-for-toggle"
327	                    >
328	                      {duration}
329	                    </MenuToggle>
330	                  )}
331	                  onOpenChange={setIsOpen}
332	                >
333	                  <SelectList>{selectOptions}</SelectList>
334	                </Select>
335	              </FormGroup>
336	            </GridItem>
337	            <GridItem sm={4} md={5}>
338	              <FormGroup label={t('Until...')}>
339	                {duration === durationOff ? (
340	                  <DatetimeTextInput
341	                    data-test="silence-until"
342	                    isRequired
343	                    onChange={(_event, value: string) => setEndsAt(value)}
344	                    value={endsAt}
345	                  />
346	                ) : (
347	                  <DatetimeTextInput
348	                    data-test="silence-until"
349	                    isDisabled
350	                    value={
351	                      isStartNow
352	                        ? t('{{duration}} from now', { duration: durations[duration] })
353	                        : getEndsAtValue()
354	                    }
355	                  />
356	                )}
357	              </FormGroup>
358	            </GridItem>
359	          </Grid>
360	          <FormGroup role="group">
361	            <Checkbox
362	              id="start-immediately"
363	              label={t('Start immediately')}
364	              isChecked={isStartNow}
365	              onChange={(e) => setIsStartNow(e.currentTarget.checked)}
366	            />
367	          </FormGroup>
368	
369	          <Title headingLevel="h2">{t('Alert labels')}</Title>
370	          <FormHelperText>
371	            <HelperText>
372	              <HelperTextItem variant="indeterminate">
373	                <Trans t={t}>
374	                  Alerts with labels that match these selectors will be silenced instead of firing.
375	                  Label values can be matched exactly or with a{' '}
376	                  <ExternalLink
377	                    href="https://github.com/google/re2/wiki/Syntax"
378	                    text={t('regular expression')}
379	                  />
380	                </Trans>
381	              </HelperTextItem>
382	            </HelperText>
383	          </FormHelperText>
384	
385	          {_.map(matchers, (matcher, i: number) => (
386	            <Grid key={i} sm={12} md={4} hasGutter>
387	              <GridItem>
388	                <FormGroup label={t('Label name')}>
389	                  <TextInput
390	                    aria-label={t('Label name')}
391	                    isRequired
392	                    onChange={(_e, v: string) =>
393	                      typeof _e === 'string'
394	                        ? setMatcherField(i, 'name', _e)
395	                        : setMatcherField(i, 'name', v)
396	                    }
397	                    placeholder={t('Name')}
398	                    value={matcher.name}
399	                  />
400	                </FormGroup>
401	              </GridItem>
402	              <GridItem>
403	                <FormGroup label={t('Label value')}>
404	                  <TextInput
405	                    aria-label={t('Label value')}
406	                    isRequired
407	                    onChange={(_e, v: string) =>
408	                      typeof _e === 'string'
409	                        ? setMatcherField(i, 'value', _e)
410	                        : setMatcherField(i, 'value', v)
411	                    }
412	                    placeholder={t('Value')}
413	                    value={matcher.value}
414	                  />
415	                </FormGroup>
416	              </GridItem>
417	              <GridItem>
418	                <FormGroup>
419	                  <div className="monitoring-silence-alert__label-options">
420	                    <FormGroup role="group" isInline>
421	                      <Checkbox
422	                        id="regex"
423	                        label={t('RegEx')}
424	                        isChecked={matcher.isRegex}
425	                        onChange={(e) => setMatcherField(i, 'isRegex', e.currentTarget.checked)}
426	                      />
427	                      <Tooltip content={<NegativeMatcherHelp />}>
428	                        <Checkbox
429	                          id="negative-matcher"
430	                          label={t('Negative matcher')}
431	                          isChecked={matcher.isEqual === false}
432	                          onChange={(e) => setMatcherField(i, 'isEqual', !e.currentTarget.checked)}
433	                        />
434	                      </Tooltip>
435	                    </FormGroup>
436	                    <Tooltip content={t('Remove')}>
437	                      <Button
438	                        type="button"
439	                        onClick={() => removeMatcher(i)}
440	                        aria-label={t('Remove')}
441	                        variant="plain"
442	                      >
443	                        <MinusCircleIcon />
444	                      </Button>
445	                    </Tooltip>
446	                  </div>
447	                </FormGroup>
448	              </GridItem>
449	            </Grid>
450	          ))}
451	
452	          <FormGroup>
453	            <Button
454	              className="pf-v5-m-link--align-left"
455	              onClick={addMatcher}
456	              type="button"
457	              variant="link"
458	              isInline
459	            >
460	              <Icon isInline size="lg" iconSize="md">
461	                <PlusCircleIcon />
462	              </Icon>
463	              {t('Add label')}
464	            </Button>
465	          </FormGroup>
466	
467	          <Title headingLevel="h2">{t('Info')}</Title>
468	          <FormGroup label={t('Creator')} isRequired>
469	            <TextInput
470	              aria-label={t('Creator')}
471	              isRequired
472	              onChange={(_e, v: string) =>
473	                typeof _e === 'string' ? setCreatedBy(_e) : setCreatedBy(v)
474	              }
475	              value={createdBy}
476	            />
477	          </FormGroup>
478	          <FormGroup label={t('Comment')} isRequired>
479	            <TextArea
480	              aria-label={t('Comment')}
481	              isRequired
482	              onChange={(_e, v: string) =>
483	                typeof _e === 'string' ? setComment(_e) : setComment(v)
484	              }
485	              data-test="silence-comment"
486	              value={comment}
487	              validated={error ? ValidatedOptions.error : ValidatedOptions.default}
488	            />
489	          </FormGroup>
490	          <ActionGroup>
491	            <Button type="submit" variant="primary" isDisabled={inProgress}>
492	              {t('Silence')}
493	            </Button>
494	            <Button onClick={history.goBack} variant="secondary" isDisabled={inProgress}>
495	              {t('Cancel')}
496	            </Button>
497	          </ActionGroup>
498	        </Form>
499	      </PageSection>
500	    </>
501	  );
502	};
503	const SilenceForm = withFallback(withRouter(SilenceForm_));
504	
505	const EditInfo = () => {
506	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
507	
508	  return (
509	    <Alert isInline title={t('Overwriting current silence')} variant="info">
510	      {t(
511	        'When changes are saved, the currently existing silence will be expired and a new silence with the new configuration will take its place.',
512	      )}
513	    </Alert>
514	  );
515	};
516	
517	export const EditSilence = ({ match }) => {
518	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
519	  const { silencesKey, perspective } = usePerspective();
520	
521	  const silences: Silences = useSelector((state: MonitoringState) =>
522	    getLegacyObserveState(perspective, state)?.get(silencesKey),
523	  );
524	
525	  const silence: Silence = _.find(silences?.data, { id: match.params.id });
526	  const isExpired = silenceState(silence) === SilenceStates.Expired;
527	  const defaults = _.pick(silence, [
528	    'comment',
529	    'createdBy',
530	    'endsAt',
531	    'id',
532	    'matchers',
533	    'startsAt',
534	  ]);
535	  defaults.startsAt = isExpired ? undefined : formatDate(new Date(defaults.startsAt));
536	  defaults.endsAt = isExpired ? undefined : formatDate(new Date(defaults.endsAt));
537	
538	  return (
539	    <StatusBox
540	      data={silence}
541	      label={SilenceResource.label}
542	      loaded={silences?.loaded}
543	      loadError={silences?.loadError}
544	    >
545	      <SilenceForm
546	        defaults={defaults}
547	        Info={isExpired ? undefined : EditInfo}
548	        title={isExpired ? t('Recreate silence') : t('Edit silence')}
549	      />
550	    </StatusBox>
551	  );
552	};
553	
554	export const CreateSilence = () => {
555	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
556	
557	  const matchers = _.map(getAllQueryArguments(), (value, name) => ({
558	    name,
559	    value,
560	    isRegex: false,
561	  }));
562	
563	  return _.isEmpty(matchers) ? (
564	    <SilenceForm defaults={{}} title={t('Create silence')} />
565	  ) : (
566	    <SilenceForm defaults={{ matchers }} title={t('Silence alert')} />
567	  );
568	};

