 69	const formatDate = (d: Date): string =>
 70	  `${d.getFullYear()}/${pad(d.getMonth() + 1)}/${pad(d.getDate())} ${pad(d.getHours())}:${pad(
 71	    d.getMinutes(),
 72	  )}:${pad(d.getSeconds())}`;
 73	
 74	const DatetimeTextInput = (props) => {
 75	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 76	
 77	  const pattern =
 78	    '\\d{4}/(0?[1-9]|1[012])/(0?[1-9]|[12]\\d|3[01]) (0?\\d|1\\d|2[0-3]):[0-5]\\d(:[0-5]\\d)?';
 79	  const isValid = new RegExp(`^${pattern}$`).test(props.value) || props.value === 'Now';
 80	
 81	  const date = props.value === 'Now' ? new Date() : new Date(props.value);
 82	
 83	  return (
 84	    <Tooltip
 85	      content={
 86	        <Timestamp date={date}>{isValid ? date.toISOString() : t('Invalid date / time')}</Timestamp>
 87	      }
