113	          {t(
114	            'If both the RegEx and negative matcher options are selected, the label value must not match the regular expression.',
115	          )}
116	        </DescriptionListDescription>
117	      </DescriptionListGroup>
118	    </DescriptionList>
119	  );
120	};
121	
122	type SilenceFormProps = RouteComponentProps & {
123	  defaults: any;
124	  Info?: React.ComponentType;
125	  title: string;
126	};
127	
128	const SilenceForm_: React.FC<SilenceFormProps> = ({ defaults, history, Info, title }) => {
129	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
130	
131	  const durationOff = '-';
132	  const durations = {
133	    [durationOff]: durationOff,
134	    '30m': t('30m'),
135	    '1h': t('1h'),
136	    '2h': t('2h'),
137	    '6h': t('6h'),
138	    '12h': t('12h'),
139	    '1d': t('1d'),
140	    '2d': t('2d'),
141	    '1w': t('1w'),
142	  };
143	
144	  const now = new Date();
145	
146	  // Default to starting now if we have no default start time or if the default start time is in the
