159	      defaultDuration = durationFromDefaults;
160	    }
161	  }
162	
163	  const dispatch = useDispatch();
164	
165	  const { perspective, silencesKey } = usePerspective();
166	
167	  const [isOpen, setIsOpen, , setClosed] = useBoolean(false);
168	
169	  const [comment, setComment] = React.useState(defaults.comment ?? '');
170	  const [createdBy, setCreatedBy] = React.useState(defaults.createdBy ?? '');
171	  const [duration, setDuration] = React.useState(defaultDuration);
172	  const [endsAt, setEndsAt] = React.useState(
173	    defaults.endsAt ?? formatDate(new Date(new Date(now).setHours(now.getHours() + 2))),
174	  );
175	  const [error, setError] = React.useState<string>();
176	  const [inProgress, setInProgress] = React.useState(false);
177	  const [isStartNow, setIsStartNow] = React.useState(defaultIsStartNow);
178	  const [matchers, setMatchers] = React.useState(
179	    defaults.matchers ?? [{ isRegex: false, name: '', value: '' }],
180	  );
181	  const [startsAt, setStartsAt] = React.useState(defaults.startsAt ?? formatDate(now));
182	  const user = useSelector(getUser);
183	  const [namespace] = useActiveNamespace();
184	
185	  React.useEffect(() => {
186	    if (!createdBy && user) {
187	      setCreatedBy(user.metadata?.name || user.username);
188	    }
189	    // eslint-disable-next-line react-hooks/exhaustive-deps
190	  }, [user]);
191	
192	  const getEndsAtValue = (): string => {
193	    const startsAtDate = Date.parse(startsAt);
194	    return startsAtDate
195	      ? formatDate(new Date(startsAtDate + parsePrometheusDuration(duration)))
196	      : '-';
197	  };
198	
199	  const setMatcherField = (i: number, field: string, v: any): void => {
200	    const newMatchers = _.clone(matchers);
201	    _.set(newMatchers, [i, field], v);
202	    setMatchers(newMatchers);
203	  };
204	
205	  const addMatcher = (): void => {
206	    setMatchers([...matchers, { isRegex: false, name: '', value: '' }]);
207	  };
208	
209	  const removeMatcher = (i: number): void => {
210	    const newMatchers = _.clone(matchers);
211	    newMatchers.splice(i, 1);
212	
213	    // If all matchers have been removed, add back a single blank matcher
214	    setMatchers(_.isEmpty(newMatchers) ? [{ isRegex: false, name: '', value: '' }] : newMatchers);
215	  };
216	
217	  const onSubmit: React.FormEventHandler<HTMLFormElement> = (e) => {
218	    e.preventDefault();
219	
220	    // Don't allow comments to only contain whitespace
221	    if (_.trim(comment) === '') {
222	      setError('Comment is required.');
223	      return;
224	    }
225	
226	    const url = getFetchSilenceAlertUrl(perspective, namespace);
227	    if (!url) {
228	      setError('Alertmanager URL not set');
229	      return;
230	    }
231	
232	    setInProgress(true);
233	
234	    const saveStartsAt: Date = isStartNow ? new Date() : new Date(startsAt);
235	    const saveEndsAt: Date =
236	      duration === durationOff
237	        ? new Date(endsAt)
238	        : new Date(saveStartsAt.getTime() + parsePrometheusDuration(duration));
239	
240	    const body = {
241	      comment,
242	      createdBy,
243	      endsAt: saveEndsAt.toISOString(),
244	      id: defaults.id,
245	      matchers,
246	      startsAt: saveStartsAt.toISOString(),
247	    };
248	
249	    consoleFetchJSON
250	      .post(getFetchSilenceAlertUrl(perspective, namespace), body)
251	      .then(({ silenceID }) => {
252	        setError(undefined);
253	        refreshSilences(dispatch, perspective, silencesKey, namespace);
254	        history.push(getSilenceAlertUrl(perspective, silenceID, namespace));
255	      })
256	      .catch((err) => {
257	        const errorMessage =
258	          typeof _.get(err, 'json') === 'string'
259	            ? _.get(err, 'json')
260	            : err.message || 'Error saving Silence';
261	        setError(errorMessage);
262	        setInProgress(false);
263	      });
264	  };
265	
266	  const selectOptions = _.map(durations, (displayText, key) => (
267	    <SelectOption key={key} value={key}>
268	      {displayText}
269	    </SelectOption>
270	  ));
271	
272	  return (
273	    <>
274	      <Helmet>
275	        <title>{title}</title>
276	      </Helmet>
277	      <PageSection>
278	        <Title headingLevel="h1">{title}</Title>
279	        <HelperText>
280	          <HelperTextItem className="monitoring__title-help-text">
281	            {t(
282	              'Silences temporarily mute alerts based on a set of label selectors that you define. Notifications will not be sent for alerts that match all the listed values or regular expressions.',
283	            )}
284	          </HelperTextItem>
285	        </HelperText>
286	      </PageSection>
287	      <Divider />
288	
289	      <PageSection>
290	        <Form onSubmit={onSubmit} maxWidth="950px">
291	          {Info && <Info />}
292	          {error && <Alert variant="danger" isInline title={error} />}
293	          <Title headingLevel="h2">{t('Duration')}</Title>
294	          <Grid hasGutter>
295	            <GridItem sm={4} md={5}>
296	              <FormGroup label={t('Silence alert from...')}>
297	                {isStartNow ? (
298	                  <DatetimeTextInput isDisabled data-test="silence-from" value={t('Now')} />
299	                ) : (
300	                  <DatetimeTextInput
301	                    data-test="silence-from"
302	                    isRequired
303	                    onChange={(_event, value: string) => setStartsAt(value)}
304	                    value={startsAt}
305	                  />
306	                )}
307	              </FormGroup>
