128	const SilenceForm_: React.FC<SilenceFormProps> = ({ defaults, history, Info, title }) => {
129	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
130	
131	  const durationOff = '-';
132	  const durations = {
133	    [durationOff]: durationOff,
134	    '30m': t('30m'),
135	    '1h': t('1h'),
136	    '2h': t('2h'),
137	    '6h': t('6h'),
138	    '12h': t('12h'),
139	    '1d': t('1d'),
140	    '2d': t('2d'),
141	    '1w': t('1w'),
142	  };
143	
144	  const now = new Date();
145	
146	  // Default to starting now if we have no default start time or if the default start time is in the
147	  // past (because Alertmanager will change a time in the past to the current time on save anyway)
148	  const defaultIsStartNow = _.isEmpty(defaults.startsAt) || new Date(defaults.startsAt) < now;
149	
150	  let defaultDuration = _.isEmpty(defaults.endsAt) ? '2h' : durationOff;
151	
152	  // If we have both a default start and end time and the difference between them exactly matches
153	  // one of the duration options, automatically select that option in the duration menu
154	  if (!defaultIsStartNow && defaults.startsAt && defaults.endsAt) {
155	    const durationFromDefaults = formatPrometheusDuration(
156	      Date.parse(defaults.endsAt) - Date.parse(defaults.startsAt),
157	    );
158	    if (Object.keys(durations).includes(durationFromDefaults)) {
159	      defaultDuration = durationFromDefaults;
160	    }
161	  }
162	
163	  const dispatch = useDispatch();
164	
165	  const { perspective, silencesKey } = usePerspective();
166	
167	  const [isOpen, setIsOpen, , setClosed] = useBoolean(false);
168	
169	  const [comment, setComment] = React.useState(defaults.comment ?? '');
170	  const [createdBy, setCreatedBy] = React.useState(defaults.createdBy ?? '');
171	  const [duration, setDuration] = React.useState(defaultDuration);
172	  const [endsAt, setEndsAt] = React.useState(
173	    defaults.endsAt ?? formatDate(new Date(new Date(now).setHours(now.getHours() + 2))),
174	  );
175	  const [error, setError] = React.useState<string>();
176	  const [inProgress, setInProgress] = React.useState(false);
177	  const [isStartNow, setIsStartNow] = React.useState(defaultIsStartNow);
178	  const [matchers, setMatchers] = React.useState(
179	    defaults.matchers ?? [{ isRegex: false, name: '', value: '' }],
180	  );
181	  const [startsAt, setStartsAt] = React.useState(defaults.startsAt ?? formatDate(now));
182	  const user = useSelector(getUser);
183	  const [namespace] = useActiveNamespace();
184	
185	  React.useEffect(() => {
186	    if (!createdBy && user) {
187	      setCreatedBy(user.metadata?.name || user.username);
188	    }
189	    // eslint-disable-next-line react-hooks/exhaustive-deps
190	  }, [user]);
191	
192	  const getEndsAtValue = (): string => {
193	    const startsAtDate = Date.parse(startsAt);
194	    return startsAtDate
195	      ? formatDate(new Date(startsAtDate + parsePrometheusDuration(duration)))
196	      : '-';
197	  };
198	
199	  const setMatcherField = (i: number, field: string, v: any): void => {
200	    const newMatchers = _.clone(matchers);
201	    _.set(newMatchers, [i, field], v);
202	    setMatchers(newMatchers);
203	  };
204	
205	  const addMatcher = (): void => {
206	    setMatchers([...matchers, { isRegex: false, name: '', value: '' }]);
207	  };
208	
209	  const removeMatcher = (i: number): void => {
210	    const newMatchers = _.clone(matchers);
211	    newMatchers.splice(i, 1);
212	
213	    // If all matchers have been removed, add back a single blank matcher
214	    setMatchers(_.isEmpty(newMatchers) ? [{ isRegex: false, name: '', value: '' }] : newMatchers);
215	  };
216	
217	  const onSubmit: React.FormEventHandler<HTMLFormElement> = (e) => {
218	    e.preventDefault();
219	
220	    // Don't allow comments to only contain whitespace
221	    if (_.trim(comment) === '') {
222	      setError('Comment is required.');
223	      return;
224	    }
225	
226	    const url = getFetchSilenceAlertUrl(perspective, namespace);
227	    if (!url) {
228	      setError('Alertmanager URL not set');
229	      return;
230	    }
231	
232	    setInProgress(true);
233	
234	    const saveStartsAt: Date = isStartNow ? new Date() : new Date(startsAt);
235	    const saveEndsAt: Date =
236	      duration === durationOff
237	        ? new Date(endsAt)
238	        : new Date(saveStartsAt.getTime() + parsePrometheusDuration(duration));
239	
240	    const body = {
241	      comment,
242	      createdBy,
243	      endsAt: saveEndsAt.toISOString(),
244	      id: defaults.id,
245	      matchers,
246	      startsAt: saveStartsAt.toISOString(),
247	    };
248	
249	    consoleFetchJSON
250	      .post(getFetchSilenceAlertUrl(perspective, namespace), body)
251	      .then(({ silenceID }) => {
252	        setError(undefined);
253	        refreshSilences(dispatch, perspective, silencesKey, namespace);
254	        history.push(getSilenceAlertUrl(perspective, silenceID, namespace));
255	      })
256	      .catch((err) => {
257	        const errorMessage =
258	          typeof _.get(err, 'json') === 'string'
259	            ? _.get(err, 'json')
260	            : err.message || 'Error saving Silence';
261	        setError(errorMessage);
262	        setInProgress(false);
263	      });
264	  };
265	
266	  const selectOptions = _.map(durations, (displayText, key) => (
267	    <SelectOption key={key} value={key}>
268	      {displayText}
269	    </SelectOption>
270	  ));
271	
272	  return (
273	    <>
274	      <Helmet>
275	        <title>{title}</title>
276	      </Helmet>
277	      <PageSection>
278	        <Title headingLevel="h1">{title}</Title>
279	        <HelperText>
280	          <HelperTextItem className="monitoring__title-help-text">
281	            {t(
282	              'Silences temporarily mute alerts based on a set of label selectors that you define. Notifications will not be sent for alerts that match all the listed values or regular expressions.',
283	            )}
284	          </HelperTextItem>
285	        </HelperText>
286	      </PageSection>
287	      <Divider />
288	
289	      <PageSection>
290	        <Form onSubmit={onSubmit} maxWidth="950px">
291	          {Info && <Info />}
292	          {error && <Alert variant="danger" isInline title={error} />}
293	          <Title headingLevel="h2">{t('Duration')}</Title>
294	          <Grid hasGutter>
295	            <GridItem sm={4} md={5}>
296	              <FormGroup label={t('Silence alert from...')}>
297	                {isStartNow ? (
298	                  <DatetimeTextInput isDisabled data-test="silence-from" value={t('Now')} />
299	                ) : (
300	                  <DatetimeTextInput
301	                    data-test="silence-from"
302	                    isRequired
303	                    onChange={(_event, value: string) => setStartsAt(value)}
304	                    value={startsAt}
305	                  />
306	                )}
307	              </FormGroup>
308	            </GridItem>
309	            <GridItem sm={4} md={2}>
310	              <FormGroup label={t('For...')}>
311	                <Select
312	                  data-test="silence-for"
313	                  isOpen={isOpen}
314	                  onSelect={(event: React.MouseEvent | React.ChangeEvent, value: string | number) => {
315	                    setDuration(String(value));
316	                    setClosed();
317	                  }}
318	                  toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
319	                    <MenuToggle
320	                      ref={toggleRef}
321	                      onClick={setIsOpen}
322	                      isExpanded={isOpen}
323	                      isFullWidth
324	                      data-test="silence-for-toggle"
325	                    >
326	                      {duration}
327	                    </MenuToggle>
328	                  )}
329	                  onOpenChange={setIsOpen}
330	                >
331	                  <SelectList>{selectOptions}</SelectList>
332	                </Select>
333	              </FormGroup>
334	            </GridItem>
335	            <GridItem sm={4} md={5}>
336	              <FormGroup label={t('Until...')}>
337	                {duration === durationOff ? (
338	                  <DatetimeTextInput
339	                    data-test="silence-until"
340	                    isRequired
341	                    onChange={(_event, value: string) => setEndsAt(value)}
342	                    value={endsAt}
343	                  />
344	                ) : (
345	                  <DatetimeTextInput
346	                    data-test="silence-until"
347	                    isDisabled
348	                    value={
349	                      isStartNow
350	                        ? t('{{duration}} from now', { duration: durations[duration] })
351	                        : getEndsAtValue()
352	                    }
353	                  />
354	                )}
355	              </FormGroup>
356	            </GridItem>
357	          </Grid>
358	          <FormGroup role="group">
359	            <Checkbox
360	              id="start-immediately"
361	              label={t('Start immediately')}
362	              isChecked={isStartNow}
363	              onChange={(e) => setIsStartNow(e.currentTarget.checked)}
364	            />
365	          </FormGroup>
366	
367	          <Title headingLevel="h2">{t('Alert labels')}</Title>
368	          <FormHelperText>
369	            <HelperText>
370	              <HelperTextItem variant="indeterminate">
371	                <Trans t={t}>
372	                  Alerts with labels that match these selectors will be silenced instead of firing.
373	                  Label values can be matched exactly or with a{' '}
374	                  <ExternalLink
375	                    href="https://github.com/google/re2/wiki/Syntax"
376	                    text={t('regular expression')}
377	                  />
378	                </Trans>
379	              </HelperTextItem>
380	            </HelperText>
381	          </FormHelperText>
382	
383	          {_.map(matchers, (matcher, i: number) => (
384	            <Grid key={i} sm={12} md={4} hasGutter>
385	              <GridItem>
386	                <FormGroup label={t('Label name')}>
387	                  <TextInput
388	                    aria-label={t('Label name')}
389	                    isRequired
390	                    onChange={(_e, v: string) =>
391	                      typeof _e === 'string'
392	                        ? setMatcherField(i, 'name', _e)
393	                        : setMatcherField(i, 'name', v)
394	                    }
395	                    placeholder={t('Name')}
396	                    value={matcher.name}
397	                  />
398	                </FormGroup>
399	              </GridItem>
400	              <GridItem>
401	                <FormGroup label={t('Label value')}>
402	                  <TextInput
403	                    aria-label={t('Label value')}
404	                    isRequired
405	                    onChange={(_e, v: string) =>
406	                      typeof _e === 'string'
407	                        ? setMatcherField(i, 'value', _e)
408	                        : setMatcherField(i, 'value', v)
409	                    }
410	                    placeholder={t('Value')}
411	                    value={matcher.value}
412	                  />
413	                </FormGroup>
414	              </GridItem>
415	              <GridItem>
416	                <FormGroup>
417	                  <div className="monitoring-silence-alert__label-options">
418	                    <FormGroup role="group" isInline>
419	                      <Checkbox
420	                        id="regex"
421	                        label={t('RegEx')}
422	                        isChecked={matcher.isRegex}
423	                        onChange={(e) => setMatcherField(i, 'isRegex', e.currentTarget.checked)}
424	                      />
425	                      <Tooltip content={<NegativeMatcherHelp />}>
426	                        <Checkbox
427	                          id="negative-matcher"
428	                          label={t('Negative matcher')}
429	                          isChecked={matcher.isEqual === false}
430	                          onChange={(e) => setMatcherField(i, 'isEqual', !e.currentTarget.checked)}
431	                        />
432	                      </Tooltip>
433	                    </FormGroup>
434	                    <Tooltip content={t('Remove')}>
435	                      <Button
436	                        type="button"
437	                        onClick={() => removeMatcher(i)}
438	                        aria-label={t('Remove')}
439	                        variant="plain"
440	                        icon={<MinusCircleIcon />}
441	                      />
442	                    </Tooltip>
443	                  </div>
444	                </FormGroup>
445	              </GridItem>
446	            </Grid>
447	          ))}
448	
449	          <FormGroup>
450	            <Button
451	              className="pf-v5-m-link--align-left"
452	              onClick={addMatcher}
453	              type="button"
454	              variant="link"
455	              isInline
456	              icon={<PlusCircleIcon />}
457	            >
458	              {t('Add label')}
459	            </Button>
460	          </FormGroup>
461	
462	          <Title headingLevel="h2">{t('Info')}</Title>
463	          <FormGroup label={t('Creator')} isRequired>
464	            <TextInput
