477	              onChange={(_e, v: string) =>
478	                typeof _e === 'string' ? setComment(_e) : setComment(v)
479	              }
480	              data-test="silence-comment"
481	              value={comment}
482	              validated={error ? ValidatedOptions.error : ValidatedOptions.default}
483	            />
484	          </FormGroup>
485	          <ActionGroup>
486	            <Button type="submit" variant="primary" isDisabled={inProgress}>
487	              {t('Silence')}
488	            </Button>
489	            <Button onClick={history.goBack} variant="secondary" isDisabled={inProgress}>
490	              {t('Cancel')}
491	            </Button>
492	          </ActionGroup>
493	        </Form>
494	      </PageSection>
495	    </>
496	  );
